{
    private readonly List<(string Title, string Content)> _notes = [];
    private readonly HttpClient _http = new()
    {
        Timeout = TimeSpan.FromSeconds(20),
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
        },
    };

    public void ClearNotes() => _notes.Clear();

    // ── Web Search ──────────────────────────────

    [Description("Search the web for information. Returns result snippets and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query")] string query)
    {
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}"
                + "&format=json&no_html=1&skip_disambig=1";

        var json = await _http.GetStringAsync(url);
        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        var sb = new StringBuilder();

        // Abstract / instant answer
        if (root.TryGetProperty("Abstract", out var abs)
            && abs.GetString() is { Length: > 0 } abstractText)
        {
            sb.AppendLine($"## Summary\n{abstractText}");
            if (root.TryGetProperty("AbstractURL", out var srcUrl))
                sb.AppendLine($"Source: {srcUrl.GetString()}");
            sb.AppendLine();
        }

        // Related topics
        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            int count = 0;
            foreach (var topic in topics.EnumerateArray())
            {
                if (count >= 8) break;
                if (topic.TryGetProperty("Text", out var text)
                    && text.GetString() is { Length: > 0 } t)
                {
                    sb.AppendLine($"- {t}");
                    if (topic.TryGetProperty("FirstURL", out var tUrl))
                        sb.AppendLine($"  URL: {tUrl.GetString()}");
                    count++;
                }
            }
        }

        var result = sb.ToString();
        Console.WriteLine($"  🌐  Searched: \"{query}\"");
        return string.IsNullOrWhiteSpace(result)
            ? "No results found. Try rephrasing or using a more specific query."
            : result;
    }

    // ── Read Web Page ───────────────────────────

    [Description("Fetch and read the text content of a web page. "
               + "Use this to get detailed information from a URL found in search results.")]
    public async Task<string> ReadWebPageAsync(
        [Description("The full URL of the web page to read")] string url)
    {
        try
        {
            var html = await _http.GetStringAsync(url);

            // Strip scripts, styles, and tags
            var text = Regex.Replace(html,
                @"<(script|style)[^>]*>.*?</\1>", "",
                RegexOptions.Singleline | RegexOptions.IgnoreCase);
            text = Regex.Replace(text, @"<[^>]+>", " ");
            text = WebUtility.HtmlDecode(text);
            text = Regex.Replace(text, @"\s+", " ").Trim();

            Console.WriteLine($"  📄  Read page: {url}");
            return text.Length > 4000 ? text[..4000] + "\n... [truncated]" : text;
        }
        catch (Exception ex)
        {
            return $"Error reading {url}: {ex.Message}";
        }
    }

    // ── Notes ───────────────────────────────────

    [Description("Save a research note. Use this to record important findings.")]
    public string SaveNote(
        [Description("A short descriptive title")] string title,
        [Description("The note content with key facts")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝  Note saved: \"{title}\"");
        return $"Note saved: \"{title}\" (Total notes: {_notes.Count})";
    }

    [Description("Retrieve all saved research notes so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"### Note {i + 1}: {_notes[i].Title}");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine("---");
        }

        return sb.ToString();
    }
}

